import{i as e,r as t,s as n,t as r}from"./app-DRIoFJCO.js";var i=JSON.parse(`{"path":"/docs/js/%E7%AB%8B%E7%BB%98.html","title":"立绘","lang":"zh-CN","frontmatter":{"description":"说明Dvnge视觉小说引擎的立绘系统，包括立绘显示、切换、隐藏、变量路径等操作方法。"},"filePathRelative":"docs/js/立绘.md","git":{}}`),a={name:`立绘.md`};function o(r,i,a,o,s,c){return n(),t(`div`,null,[...i[0]||=[e(`<h1 id="立绘" tabindex="-1"><a class="header-anchor" href="#立绘"><span>立绘</span></a></h1><p>本章介绍怎么使用Dvnge来操作立绘。</p><h2 id="立绘显示" tabindex="-1"><a class="header-anchor" href="#立绘显示"><span>立绘显示</span></a></h2><p>视觉小说一般都少不了立绘，要在Dvnge设置显示它很简单：</p><div class="language-javascript line-numbers-mode" data-highlighter="prismjs" data-ext="js"><pre><code class="language-javascript"><span class="line"><span class="token literal-property property">立绘</span><span class="token operator">:</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token literal-property property">中立绘</span><span class="token operator">:</span> <span class="token punctuation">{</span> <span class="token literal-property property">路径</span><span class="token operator">:</span> <span class="token string">&quot;assets/img/立绘.png&quot;</span> <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>其中 <code>中立绘</code> 可以换成 <code>左立绘</code> 或 <code>右立绘</code>，也支持一次显示多个：</p><div class="language-javascript line-numbers-mode" data-highlighter="prismjs" data-ext="js"><pre><code class="language-javascript"><span class="line"><span class="token literal-property property">立绘</span><span class="token operator">:</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token literal-property property">左立绘</span><span class="token operator">:</span> <span class="token punctuation">{</span> <span class="token literal-property property">路径</span><span class="token operator">:</span> <span class="token string">&quot;&quot;</span> <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token literal-property property">中立绘</span><span class="token operator">:</span> <span class="token punctuation">{</span> <span class="token literal-property property">路径</span><span class="token operator">:</span> <span class="token string">&quot;&quot;</span> <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token literal-property property">右立绘</span><span class="token operator">:</span> <span class="token punctuation">{</span> <span class="token literal-property property">路径</span><span class="token operator">:</span> <span class="token string">&quot;&quot;</span> <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>立绘</code> 和 <code>音乐</code> 等一样，是会默认延续到下一节点的。</p><h2 id="立绘切换" tabindex="-1"><a class="header-anchor" href="#立绘切换"><span>立绘切换</span></a></h2><div class="language-javascript line-numbers-mode" data-highlighter="prismjs" data-ext="js"><pre><code class="language-javascript"><span class="line"><span class="token punctuation">{</span></span>
<span class="line">    <span class="token literal-property property">角色</span><span class="token operator">:</span> <span class="token string">&quot;Tian&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token literal-property property">内容</span><span class="token operator">:</span> <span class="token string">&quot;设置立绘&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token literal-property property">立绘</span><span class="token operator">:</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token literal-property property">中立绘</span><span class="token operator">:</span> <span class="token punctuation">{</span> <span class="token literal-property property">路径</span><span class="token operator">:</span> <span class="token string">&quot;assets/img/立绘1.png&quot;</span> <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    <span class="token literal-property property">角色</span><span class="token operator">:</span> <span class="token string">&quot;Tian&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token literal-property property">内容</span><span class="token operator">:</span> <span class="token string">&quot;默认延续上一节点设置的立绘（继续显示立绘1）&quot;</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    <span class="token literal-property property">角色</span><span class="token operator">:</span> <span class="token string">&quot;Tian&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token literal-property property">内容</span><span class="token operator">:</span> <span class="token string">&quot;切换立绘，直接更换路径即可&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token literal-property property">立绘</span><span class="token operator">:</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token literal-property property">中立绘</span><span class="token operator">:</span> <span class="token punctuation">{</span> <span class="token literal-property property">路径</span><span class="token operator">:</span> <span class="token string">&quot;assets/img/立绘2.png&quot;</span> <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="立绘隐藏" tabindex="-1"><a class="header-anchor" href="#立绘隐藏"><span>立绘隐藏</span></a></h2><div class="language-javascript line-numbers-mode" data-highlighter="prismjs" data-ext="js"><pre><code class="language-javascript"><span class="line"><span class="token literal-property property">立绘</span><span class="token operator">:</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token literal-property property">中立绘</span><span class="token operator">:</span> <span class="token punctuation">{</span> <span class="token literal-property property">隐藏</span><span class="token operator">:</span> <span class="token boolean">true</span> <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>如果说要在同一个节点隐藏一个立绘显示/切换一个立绘就这样写：</p><div class="language-javascript line-numbers-mode" data-highlighter="prismjs" data-ext="js"><pre><code class="language-javascript"><span class="line"><span class="token literal-property property">立绘</span><span class="token operator">:</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token literal-property property">右立绘</span><span class="token operator">:</span> <span class="token punctuation">{</span> <span class="token literal-property property">隐藏</span><span class="token operator">:</span> <span class="token boolean">true</span> <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token literal-property property">左立绘</span><span class="token operator">:</span> <span class="token punctuation">{</span> <span class="token literal-property property">路径</span><span class="token operator">:</span> <span class="token string">&quot;assets/img/立绘.png&quot;</span> <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="变量路径" tabindex="-1"><a class="header-anchor" href="#变量路径"><span>变量路径</span></a></h2><p>这个一般用在玩家有多个选择，而立绘会随着玩家的选择而不同的情况下使用。比如：</p><p><img src="/docsImg/%E5%A5%B3or%E7%94%B7.webp" alt="女or男.webp"></p><p>因为选择的不同玩家立绘也会不一样，玩家选择什么开发者是不可预测的。这个时候就需要变量路径，设置方法如下，我们以上面展示的选项为例：</p><div class="language-javascript line-numbers-mode" data-highlighter="prismjs" data-ext="js"><pre><code class="language-javascript"><span class="line"><span class="token punctuation">{</span></span>
<span class="line">    <span class="token literal-property property">内容</span><span class="token operator">:</span> <span class="token string">&quot;说起来我还没有问你，你是男生还是女生？&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token literal-property property">选项</span><span class="token operator">:</span> <span class="token punctuation">[</span></span>
<span class="line">        <span class="token punctuation">{</span></span>
<span class="line">            <span class="token literal-property property">文本</span><span class="token operator">:</span> <span class="token string">&quot;我是女生&quot;</span><span class="token punctuation">,</span></span>
<span class="line">            <span class="token literal-property property">设置变量</span><span class="token operator">:</span> <span class="token punctuation">{</span></span>
<span class="line">                <span class="token string-property property">&quot;玩家性别&quot;</span><span class="token operator">:</span> <span class="token string">&quot;女&quot;</span></span>
<span class="line">            <span class="token punctuation">}</span></span>
<span class="line">        <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">        <span class="token punctuation">{</span></span>
<span class="line">            <span class="token literal-property property">文本</span><span class="token operator">:</span> <span class="token string">&quot;我是男生&quot;</span><span class="token punctuation">,</span></span>
<span class="line">            <span class="token literal-property property">设置变量</span><span class="token operator">:</span> <span class="token punctuation">{</span></span>
<span class="line">                <span class="token string-property property">&quot;玩家性别&quot;</span><span class="token operator">:</span> <span class="token string">&quot;男&quot;</span></span>
<span class="line">            <span class="token punctuation">}</span></span>
<span class="line">        <span class="token punctuation">}</span></span>
<span class="line">    <span class="token punctuation">]</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    <span class="token literal-property property">立绘</span><span class="token operator">:</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token literal-property property">中立绘</span><span class="token operator">:</span> <span class="token punctuation">{</span> <span class="token literal-property property">路径</span><span class="token operator">:</span> <span class="token string">&quot;主控_{玩家性别}.png&quot;</span> <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>如果选择“我是女生”，那玩家的立绘就会是 <code>主控_女.png</code> ，反之则是 <code>主控_男.png</code> 。</p><h2 id="视频立绘" tabindex="-1"><a class="header-anchor" href="#视频立绘"><span>视频立绘</span></a></h2><p>这个一般情况下用不上，不过以防万一有一些特殊需求，引擎还是加入了该功能。</p>`,22)]])}var s=r(a,[[`render`,o]]);export{i as _pageData,s as default};